import { Link, useLocation, useNavigate } from "react-router-dom";
import { motion } from "framer-motion";
import { Menu, X } from "lucide-react";
import { useEffect, useState } from "react";
import logo from "@/assets/logo.png";
import { getUser, logout, subscribeAuth } from "@/lib/auth";

const publicLinks = [
  { href: "/", label: "Главная" },
  { href: "/courses", label: "Курсы" },
];

const privateLinks = [
  { href: "/dashboard", label: "Мой профиль" },
  { href: "/courses", label: "Курсы" },
];

interface HeaderProps {
  transparent?: boolean;
}

const Header = ({ transparent = false }: HeaderProps) => {
  const [mobileOpen, setMobileOpen] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();
  const [isLoggedIn, setIsLoggedIn] = useState(() => Boolean(getUser()));

  useEffect(() => {
    return subscribeAuth(() => setIsLoggedIn(Boolean(getUser())));
  }, []);

  return (
    <motion.header
      initial={{ opacity: 0, y: -20 }}
      animate={{ opacity: 1, y: 0 }}
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 ${
        transparent
          ? "bg-transparent"
          : "bg-card/80 backdrop-blur-2xl border-b border-border/30 shadow-card"
      }`}
    >
      <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
        {/* Logo */}
        <Link to="/" className="flex items-center group">
          <img src={logo} alt="AcademicApply" className="h-10 w-auto object-contain group-hover:scale-105 transition-transform mix-blend-multiply dark:mix-blend-screen" />
        </Link>

        {/* Desktop Nav */}
        <nav className="hidden md:flex items-center gap-1">
          {(isLoggedIn ? privateLinks : publicLinks).map((link) => {
            const isActive = location.pathname === link.href;
            return (
              <Link
                key={link.href}
                to={link.href}
                className={`px-4 py-2 rounded-full text-sm font-medium transition-all duration-300 ${
                  isActive
                    ? transparent
                      ? "bg-card/20 text-primary-foreground"
                      : "bg-primary/10 text-primary"
                    : transparent
                    ? "text-primary-foreground/70 hover:text-primary-foreground hover:bg-card/10"
                    : "text-muted-foreground hover:text-foreground hover:bg-muted"
                }`}
              >
                {link.label}
              </Link>
            );
          })}
        </nav>

        {/* Desktop CTA */}
        <div className="hidden md:flex items-center gap-3">
          {isLoggedIn ? (
            <>
              <button
                type="button"
                onClick={() => logout()}
                className="px-6 py-2.5 rounded-full bg-muted text-foreground text-sm font-semibold hover:bg-muted/80 transition-all duration-300"
              >
                Выйти
              </button>
            </>
          ) : (
            <Link
              to="/login"
              className="px-6 py-2.5 rounded-full bg-primary text-primary-foreground text-sm font-semibold hover:bg-primary/90 transition-all duration-300 shadow-md hover:shadow-lg"
            >
              Login
            </Link>
          )}
        </div>

        {/* Mobile menu toggle */}
        <button
          onClick={() => setMobileOpen(!mobileOpen)}
          className={`md:hidden p-2 rounded-lg ${transparent ? "text-primary-foreground" : "text-foreground"}`}
        >
          {mobileOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
        </button>
      </div>

      {/* Mobile menu */}
      {mobileOpen && (
        <motion.div
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          className="md:hidden bg-card/95 backdrop-blur-2xl border-b border-border/30 px-4 py-4 space-y-2 rounded-b-3xl shadow-card"
        >
          {(isLoggedIn ? privateLinks : publicLinks).map((link) => (
            <Link
              key={link.href}
              to={link.href}
              onClick={() => setMobileOpen(false)}
              className="block px-4 py-3 rounded-2xl text-sm font-medium text-foreground hover:bg-muted transition-all duration-300"
            >
              {link.label}
            </Link>
          ))}
          {isLoggedIn && (
            <>
              <button
                type="button"
                onClick={() => {
                  logout();
                  setMobileOpen(false);
                }}
                className="w-full px-4 py-3 rounded-2xl bg-muted text-foreground text-sm font-semibold text-center shadow-md"
              >
                Выйти
              </button>
            </>
          )}
          {!isLoggedIn && (
            <Link
              to="/login"
              onClick={() => setMobileOpen(false)}
              className="block px-4 py-3 rounded-2xl bg-primary text-primary-foreground text-sm font-semibold text-center shadow-md"
            >
              Login
            </Link>
          )}
        </motion.div>
      )}
    </motion.header>
  );
};

export default Header;
