import { useEffect, useMemo } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import { motion } from "framer-motion";
import { Sparkles, Lock, ArrowRight } from "lucide-react";
import Header from "@/components/Header";
import Footer from "@/components/Footer";
import { Button } from "@/components/ui/button";
import { ensureOrganicAttribution, getAttribution } from "@/lib/attribution";
import { isAuthed } from "@/lib/auth";
import { universityData } from "@/data/universities";

const Paywall = () => {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const isUpgradeFlow = searchParams.get("upgrade") === "1";
  const authed = isAuthed();

  const showPlans = authed || isUpgradeFlow;

  const recommendedCountries = useMemo(() => {
    const keys = ["target_country", "school_target_country", "country", "graduate_target_country"];
    const fromParams = keys
      .flatMap((k) => (searchParams.get(k) || "").split(","))
      .map((v) => v.trim())
      .filter(Boolean);

    const normalized = fromParams
      .flatMap((v) => {
        if (v === "Другая") {
          return [];
        }
        if (v === "Южная Корея") {
          return ["Южная Корея"];
        }
        return [v];
      })
      .filter((v) => v !== "Не имеет значения");

    const unique = Array.from(new Set(normalized));
    return unique.length ? unique.slice(0, 4) : ["Казахстан", "Великобритания", "Германия", "Южная Корея"];
  }, [searchParams]);

  const recommendedUniversities = useMemo(() => {
    const filtered = universityData
      .filter((u) => recommendedCountries.includes(u.country))
      .sort((a, b) => b.match - a.match);
    return filtered.slice(0, 4);
  }, [recommendedCountries]);

  useEffect(() => {
    ensureOrganicAttribution();
  }, []);

  useEffect(() => {
    if (!authed) return;
    if (isUpgradeFlow) return;
    navigate(`/results?${searchParams.toString()}`);
  }, [authed, isUpgradeFlow, navigate, searchParams]);

  const attr = getAttribution();
  const fromEvent = attr?.source === "offline_qr";

  return (
    <div className="min-h-screen bg-background">
      <Header />
      <div className="pt-24 pb-16 px-4">
        <div className="max-w-2xl mx-auto">
          <div className="p-8 rounded-2xl bg-card border border-border/50 shadow-card">
            <div className="flex items-center gap-3 mb-6">
              <div className="w-11 h-11 rounded-xl bg-primary/10 flex items-center justify-center">
                <Sparkles className="w-5 h-5 text-primary" />
              </div>
              <div>
                <h1 className="text-2xl font-heading font-bold text-foreground">
                  {showPlans ? "Выбери тариф" : "Мы анализируем твой профиль"}
                </h1>
                <p className="text-sm text-muted-foreground">
                  {showPlans ? "Открой полный доступ к рекомендациям" : "Секунду — собираем рекомендации"}
                </p>
              </div>
            </div>

            {!showPlans && (
              <>
                <motion.div
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  transition={{ duration: 0.6 }}
                  className="grid grid-cols-1 gap-3"
                >
                  <motion.div
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.2 }}
                    className="p-4 rounded-xl bg-primary/5 border border-primary/10"
                  >
                    <p className="text-sm text-foreground font-medium">Найдено: 12 программ</p>
                    <p className="text-xs text-muted-foreground">С шансом поступления 85%+</p>
                  </motion.div>

                  <motion.div
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.35 }}
                    className="p-4 rounded-xl bg-secondary/5 border border-secondary/10"
                  >
                    <p className="text-sm text-foreground font-medium">Топ-направление: Data Science</p>
                    <p className="text-xs text-muted-foreground">Актуальные профессии на 10 лет</p>
                  </motion.div>

                  {fromEvent && (
                    <motion.div
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      transition={{ delay: 0.5 }}
                      className="p-4 rounded-xl bg-accent/5 border border-accent/10"
                    >
                      <p className="text-sm text-foreground font-medium">Бонус участника мероприятия</p>
                      <p className="text-xs text-muted-foreground">Скидка активируется после регистрации</p>
                    </motion.div>
                  )}
                </motion.div>

                <div className="mt-8 p-4 rounded-xl bg-card border border-border/50 flex items-start gap-3">
                  <div className="w-9 h-9 rounded-lg bg-primary/10 flex items-center justify-center flex-shrink-0">
                    <Lock className="w-4 h-4 text-foreground" />
                  </div>
                  <div className="flex-1">
                    <p className="text-sm text-foreground font-medium">Открой полный список</p>
                    <p className="text-xs text-muted-foreground">Создай аккаунт, чтобы увидеть результаты и сохранить их</p>
                  </div>
                </div>
              </>
            )}

            {showPlans ? (
              <div className="mt-8">
                <div className="mb-4 p-4 rounded-xl bg-secondary/5 border border-secondary/10">
                  <p className="text-sm text-foreground font-medium">Сделаем прогноз точнее</p>
                  <p className="text-xs text-muted-foreground">
                    Укажи свой GPA и IELTS (если есть) — мы спрогнозируем твои шансы и подберём лучшие шаги.
                  </p>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                {/* $49 Basic Plan */}
                <motion.div
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 0.3 }}
                  className="group relative p-6 rounded-xl bg-primary/5 border border-primary/20"
                >
                  <div className="flex items-center gap-2 mb-2">
                    <span className="text-2xl font-bold text-primary">$49</span>
                    <span className="text-sm text-muted-foreground">/месяц</span>
                  </div>
                  <h3 className="font-semibold text-foreground mb-2">AI Roadmap</h3>
                  <ul className="text-sm text-muted-foreground space-y-1 mb-4">
                    <li>• 2–3 видеозвонка в неделю с консультантом</li>
                    <li>• План действий и контроль прогресса</li>
                    <li>• Помощник + подбор бесплатных курсов</li>
                  </ul>
                  <Button
                    className="w-full"
                    variant="outline"
                    onClick={() => navigate(`/checkout?plan=ai_roadmap&${searchParams.toString()}`)}
                  >
                    Выбрать
                  </Button>

                  <div className="pointer-events-none absolute inset-0 rounded-xl bg-background/95 border border-border opacity-0 transition-opacity duration-200 group-hover:opacity-100" />
                  <div className="pointer-events-none absolute inset-0 p-6 opacity-0 transition-opacity duration-200 group-hover:opacity-100">
                    <p className="text-sm font-semibold text-foreground">Todo-лист плана $49</p>
                    <ul className="mt-3 text-sm text-muted-foreground space-y-2">
                      <li>• 2–3 видеозвонка в неделю с консультантом</li>
                      <li>• Пошаговый план действий</li>
                      <li>• Помощник + AI подсказки</li>
                      <li>• Бесплатные курсы и ресурсы</li>
                    </ul>
                    <p className="mt-4 text-xs text-muted-foreground">Наведи курсор — чтобы увидеть, что входит</p>
                  </div>
                </motion.div>

                {/* $490 Expert Plan */}
                <motion.div
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 0.4 }}
                  className="group relative p-6 rounded-xl bg-gradient-to-br from-amber-100 to-yellow-100 border border-amber-300"
                >
                  <div className="flex items-center justify-between mb-2">
                    <div className="flex items-center gap-2">
                      <span className="text-2xl font-bold text-amber-600">$490</span>
                      <span className="text-sm text-muted-foreground">/3 месяца</span>
                    </div>
                    <span className="px-2 py-1 bg-amber-500 text-white text-xs rounded-full">EXPERT</span>
                  </div>
                  <h3 className="font-semibold text-foreground mb-2">Expert Mentorship</h3>
                  <ul className="text-sm text-muted-foreground space-y-1 mb-4">
                    <li>• До 2 видеосессий в день (по желанию)</li>
                    <li>• Индивидуальный план до поступления</li>
                    <li>• Документы + виза + общежитие</li>
                    <li>• Курсы + помощник</li>
                  </ul>
                  <Button
                    className="w-full bg-gradient-to-r from-amber-500 to-yellow-500 hover:from-amber-600 hover:to-yellow-600"
                    onClick={() => navigate(`/checkout?plan=expert_mentorship&${searchParams.toString()}`)}
                  >
                    Выбрать Expert
                  </Button>

                  <div className="pointer-events-none absolute inset-0 rounded-xl bg-background/95 border border-border opacity-0 transition-opacity duration-200 group-hover:opacity-100" />
                  <div className="pointer-events-none absolute inset-0 p-6 opacity-0 transition-opacity duration-200 group-hover:opacity-100">
                    <p className="text-sm font-semibold text-foreground">Todo-лист пакета $490</p>
                    <ul className="mt-3 text-sm text-muted-foreground space-y-2">
                      <li>• До 2 видеосессий в день с консультантом/экспертом</li>
                      <li>• Индивидуальный план до поступления</li>
                      <li>• Документация: мотивационное/рекомендации/заявки</li>
                      <li>• Виза и общежитие: полный разбор шагов</li>
                      <li>• Курсы + помощник + сопровождение до результата</li>
                    </ul>
                    <p className="mt-4 text-xs text-muted-foreground">Наведи курсор — чтобы увидеть, что входит</p>
                  </div>
                </motion.div>
                </div>
              </div>
            ) : (
              <div className="mt-8">
                <div className="mb-4 p-5 rounded-xl bg-secondary/5 border border-secondary/10">
                  <p className="text-sm text-foreground font-medium">Чтобы узнать больше — создай аккаунт</p>
                  <p className="text-xs text-muted-foreground mt-1">После регистрации откроются следующие шаги:</p>
                  <ul className="mt-3 text-sm text-muted-foreground space-y-2">
                    <li>• Заполни профиль (GPA/IELTS) — мы спрогнозируем твоё будущее</li>
                    <li>• Получи персональную специальность и дорожную карту</li>
                    <li>• Сохрани результаты и вернись к ним позже</li>
                  </ul>
                </div>

                <div className="p-5 rounded-xl bg-primary/5 border border-primary/10">
                  <p className="text-sm text-foreground font-medium">Рекомендуемые страны</p>
                  <div className="mt-3 flex flex-wrap gap-2">
                    {recommendedCountries.map((c) => (
                      <span key={c} className="px-3 py-1 rounded-full text-xs bg-background border border-border text-foreground">
                        {c}
                      </span>
                    ))}
                  </div>
                </div>

                <div className="mt-4 p-5 rounded-xl bg-card border border-border/50">
                  <p className="text-sm text-foreground font-medium">Подходящие университеты</p>
                  <div className="mt-3 space-y-3">
                    {recommendedUniversities.map((u) => (
                      <div key={u.id} className="flex items-center justify-between gap-3">
                        <div className="min-w-0">
                          <p className="text-sm font-medium text-foreground truncate">{u.name}</p>
                          <p className="text-xs text-muted-foreground">{u.country}, {u.city}</p>
                        </div>
                        <div className="flex-shrink-0 text-xs font-medium text-primary">{u.match}%</div>
                      </div>
                    ))}
                  </div>
                  <div className="mt-4">
                    <Button className="w-full gap-2" size="lg" onClick={() => navigate(`/register?${searchParams.toString()}`)}>
                      Создать аккаунт <ArrowRight className="w-4 h-4" />
                    </Button>
                  </div>
                </div>
              </div>
            )}

            <div className="mt-6 flex flex-col sm:flex-row gap-3">
              {!authed && showPlans && (
                <Button className="gap-2" size="lg" onClick={() => navigate(`/register?${searchParams.toString()}`)}>
                  Создать аккаунт <ArrowRight className="w-4 h-4" />
                </Button>
              )}
              {authed ? (
                <Button size="lg" onClick={() => navigate("/dashboard")}>
                  Назад в кабинет
                </Button>
              ) : (
                <Button variant="outline" size="lg" onClick={() => navigate("/")}>На главную</Button>
              )}
            </div>
          </div>
        </div>
      </div>
      <Footer />
    </div>
  );
};

export default Paywall;
